from dataclasses import dataclass, field
from datetime import date
from enum import Enum
from typing import Optional
import anthropic

class DepStatus(Enum):
    ON_TRACK = "on_track"
    AT_RISK   = "at_risk"
    BLOCKED   = "blocked"
    RESOLVED  = "resolved"

@dataclass
class Dependency:
    dep_id: str
    provider_team: str          # team that DELIVERS the dependency
    consumer_team: str          # team that NEEDS it
    capability: str             # what is being provided (e.g. "RAG Pipeline")
    due_date: date
    status: DepStatus
    notes: str = ""
    escalation_level: int = 0   # 0=none, 1=lead, 2=director, 3=exec

    def is_critical(self) -> bool:
        return self.status in (DepStatus.AT_RISK, DepStatus.BLOCKED)

@dataclass
class DependencyRegistry:
    subject: str
    stage: str
    deps: list[Dependency] = field(default_factory=list)

    def add(self, dep: Dependency) -> None:
        if any(d.dep_id == dep.dep_id for d in self.deps):
            raise ValueError(f"Duplicate dep_id {dep.dep_id}")
        self.deps.append(dep)

    def blocked(self) -> list[Dependency]:
        return [d for d in self.deps if d.status == DepStatus.BLOCKED]

    def at_risk(self) -> list[Dependency]:
        return [d for d in self.deps if d.status == DepStatus.AT_RISK]

    def by_consumer(self, team: str) -> list[Dependency]:
        return [d for d in self.deps if d.consumer_team == team]

    def critical_summary(self) -> str:
        lines = []
        for d in self.deps:
            if d.is_critical():
                symbol = "⛔" if d.status == DepStatus.BLOCKED else "⚠"
                lines.append(
                    f"{symbol} [{d.dep_id}] {d.provider_team}→{d.consumer_team}: "
                    f"{d.capability} (due {d.due_date})"
                )
        return "\n".join(lines) if lines else "No critical dependencies."

def classify_dependency_risk(dep: Dependency, context: str) -> dict:
    """Use Claude to assess whether a dependency note signals escalation risk."""
    client = anthropic.Anthropic()

    prompt = f"""You are a program management assistant tracking cross-team dependencies
for enterprise Claude AI initiatives.

Dependency: [{dep.dep_id}]
Provider: {dep.provider_team}
Consumer: {dep.consumer_team}
Capability: {dep.capability}
Due: {dep.due_date}
Current Status: {dep.status.value}
Latest Note: {dep.notes}

Additional context:
{context}

Assess:
1. Should this dependency be escalated? (true/false)
2. Recommended escalation level: 0=none, 1=team-lead, 2=director, 3=exec
3. One-sentence risk summary for the status update.
4. Proposed resolution action (one sentence).

Reply in JSON:
{{"escalate": bool, "level": int, "risk_summary": str, "action": str}}"""

    message = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        messages=[{"role": "user", "content": prompt}],
    )
    import json as _json
    return _json.loads(message.content[0].text)

# Example usage
dep = Dependency(
    dep_id="DEP-044",
    provider_team="Platform",
    consumer_team="Sales AI",
    capability="RAG Pipeline",
    due_date=date(2025, 9, 15),
    status=DepStatus.BLOCKED,
    notes="Blocked since Aug-5: vector DB provisioning pending security review sign-off.",
)
result = classify_dependency_risk(dep, context="Sales AI Proposal Gen demo scheduled Sep-20.")
# {"escalate": true, "level": 2, "risk_summary": "...", "action": "..."}
